mapper.insert:
INSERT INTO ARTICLES (
    ARTICLE_ID, TITLE, CONTENT, SUMMARY, COVER_IMAGE_ID, CATEGORY, STATUS, DEL_FLAG, CREATED_AT, UPDATED_AT
) VALUES (
    #{articleId}, #{title}, #{content}, #{summary}, #{coverImageId}, #{category}, #{status}, 0, NOW(), NOW()
