mapper.select:
SELECT ARTICLE_ID AS articleId, TITLE AS title, SUMMARY AS summary, COVER_IMAGE_ID AS coverImageId, CATEGORY AS category, STATUS AS status, VIEW_COUNT AS viewCount, PUBLISHED_AT AS publishedAt, REJECT_REASON AS rejectReason, CREATED_AT AS createdAt, UPDATED_AT AS updatedAt FROM ARTICLES WHERE DEL_FLAG = 0 AND STATUS = #{status}
AND (TITLE LIKE CONCAT('%', #{keyword}, '%') OR SUMMARY LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY UPDATED_AT DESC LIMIT #{limit} OFFSET #{offset}
